script.text:
      /* <flatten type="Javascript"> */
function load$Grid(g) {
  g._$k = [], g._$c = [], g._$r = [];
  g._$n = g._getColumnOrder('so_ct');
  g._$i = g._getColumnOrder('ma_bt');
  g._$t = g._getColumnOrder('tag');
  g._$f = 'keys';
  g.add_onResponseComplete(on$GridPeriodicTransaction$ResponseComplete);
  g.add_commandEvent(on$GridPeriodicTransaction$ExecuteCommand);
}
function scatter$Grid(g) {fill$Grid(g, true);}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$GridPeriodicTransaction$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridPeriodicTransaction$ResponseComplete);} catch (ex) {}
}
function on$GridPeriodicTransaction$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Print':
      e.type.cancelEvent = !isCheck$Grid(g);
      init$ExportKey(g, ',');
      break;
    case 'Create':
    case 'DeleteAlloc':
      request$PeriodicTransaction(g, action);
      break;
    case 'BeforeFormLoad':
      e.type.Value.set_vars([{Name: 'p', Type: 'Decimal', Value: g._p}, {Name: 'y', Type: 'Decimal', Value: g._y}, {Name: 'u', Type: 'String', Value: g._u}]);
      break;
    case 'CreateNumber':
      if (isCheck$Grid(g)) g.showForm('PeriodicTransactionCreateNumber');
      break;
    default:
      break;
  }
}
function request$PeriodicTransaction(g, c) {
  if (g._rowCount == 0) return;
  var r = (g._activeCell ? g._activeRow : 1), s = ',' + g._$k.join(',') + ',', o = g._getItemValue(r, g._$t);
  o.row = r;
  if (isCheck$Grid(g)) {
    for (i = 0; i < g._$c.length; i++) {
     if (g._$c[i] == '') {
        var e = (g._language == 'v' ? 'Chưa nhập số chứng từ.' : 'Invalid voucher number.');
        $message.show(e, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
        return;
      }
    }
    g.request(o, c, c, [['p', 'Decimal', g._p], ['y', 'Decimal', g._y], ['u', 'String', g._u], ['s', 'Infinite', s]]);
  }
}
function on$GridPeriodicTransaction$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Create':
    case 'DeleteAlloc':
      var msg = (g._language == 'v' ? 'Chương trình đã thực hiện xong.' : 'The process completed successfully.');
      $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
      g._$k = [];
      g._$c = [];
      g._$r = [];
      fill$Grid(g);
      break;
    default:
      break;
  }
}
function beforeDrillDownWithCondition(g) {g._args.cancelEvent = (g._getItemValue(g._activeRow, g._getColumnOrder('so_ct')) == '');}
function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._$k.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$k.length == 0) {
    g._$k = []; g._$c = []; g._$r = [];
    return;
  }
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r), i = Array.indexOf(g._$k, k);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r), i = Array.indexOf(g._$k, k);
    var c = g._getItemValue(r, g._$n), j = Array.indexOf(g._$r, r);
    if (i == -1) {Array.add(g._$k, k);} else {Array.removeAt(g._$k, i);}
    if (j == -1) {
      Array.add(g._$c, c]);
      Array.add(g._$r, r]);
    } else {
      Array.removeAt(g._$c, j);
      Array.removeAt(g._$r, j);
    }
    g._setItemValue(r, g._$t, (i == -1));
  }
  init$ExportKey(g);
  g._focusWhenTabChanged();
}
function onChange$SelectedValue(o) {
  var r = $func.getLocationCell(o)[0], g = $find(o.id.split('_inputCell_')[0]), k = row$Key(g, r), i = Array.indexOf(g._$k, k);
  var c = g._getItemValue(r, g._$n), j = Array.indexOf(g._$r, r);
  if (i == -1) {Array.add(g._$k, k);} else {Array.removeAt(g._$k, i);}
  if (j == -1) {
    Array.add(g._$c, c]);
    Array.add(g._$r, r]);
  } else {
    Array.removeAt(g._$c, j);
    Array.removeAt(g._$r, j);
  }
  init$ExportKey(g);
}
function init$ExportKey(g, c) {
  var p = (c ? c : ''), keys = p + g._$k.join(',') + p, v = g._filterMemvars, memvar = v[$func.findMemvarIndex(g._$f, v)];
  memvar.NewValue = memvar.Compressed ? $func.compress(keys) : keys;
}
function row$Key(g, r) {return g._getItemValue(r, g._$i);}
/* </flatten> */

css.text:

div.Edit{background-image:url(../images/Shift.png);background-repeat:no-repeat;background-position:0 0;}
div.TextEdit{background-image:url(../images/TextAsterisk.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.CreateNumber{background-image:url(../images/Highlight.png);background-repeat:no-repeat;background-position:0 0;}
div.Create{background-image:url(../images/command.png);background-repeat:no-repeat;background-position:0 0;}
div.DeleteAlloc{background-image:url(../images/command.png);background-repeat:no-repeat;background-position:-44px 0;}
div.TextCreateNumber{background-image:url(../images/TextHighlight.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.TextCreate{background-image:url(../images/TextCreate.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.TextDeleteAlloc{background-image:url(../images/TextRemove.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.EditOverGreen, div.TextEditOverGreen, div.TextCreateOverGreen, div.TextCreateNumberOverGreen, div.CreateOverGreen, div.CreateNumberOverGreen, div.DeleteAllocOverGreen, div.TextDeleteAllocOverGreen{background-position-y:-22px;}
